import React, { useEffect,  useState } from "react";
import ReactPlayer from "react-player";
import '../SommieRoomInquilino.css';
import useSommieRoomInquilino from "./useSommieRoomInquilino";
import './SommieRoomInquilino.css'

const SommieRoomInquilino = () => {
    const [currentTime, setCurrentTime] = useState(new Date());
    const {
        callStreamReal,
        atender,
        recibiendoLlamada,
    } = useSommieRoomInquilino()

    useEffect(() => {
        const timerId = setInterval(() => {
            setCurrentTime(new Date()); // Actualiza el estado con la hora actual
        }, 1000);

        return () => clearInterval(timerId); // Limpia el intervalo cuando el componente se desmonte
    }, []);



    return (
        <div className="container-call">
            <div className="container-llamada">
                <div className="call-screen">
                    <div className="notification-bar">
                        <div className="hora-bar">
                            <h3>23:13</h3>
                        </div>
                        <div className="titulo-bar">
                            <h3>CONSORCIO JUAN DOMINGO PERON</h3>
                        </div>
                    </div>
                    <div className="caller-info">
                        {recibiendoLlamada ? (
                            <>

                                {callStreamReal ? (
                                    <ReactPlayer
                                        playing
                                        height="100%"
                                        width="100%"
                                        url={callStreamReal}
                                    />
                                ) : (
                                    <>
                                        <h1 className="caller-name">Portero</h1>
                                        <p className="caller-detail">Recibiendo llamada...</p>
                                        <div className="call-actions ">
                                            <button id='btn-atender-llamada' onClick={atender} className="action-button accept">Contestar</button>
                                        </div>
                                    </>

                                )}
                            </>
                        ) : (
                            <span>No hay nadie esperando</span>
                        )}
                    </div>

                </div>
            </div>
        </div>
    );
};

export default SommieRoomInquilino;
