import { Routes, Route } from "react-router-dom";
import "./App.css";
import SommieRoomPortero from "./screens/SommieRoomPortero/SommieRoomPortero";
import SommieRoomInquilino from "./screens/SommieRoomInquilino/SommieRoomInquilino";

function App() {
  return (
    <div className="App">
      <Routes>
        <Route path="/llamar" element={<SommieRoomPortero />} />
        <Route path="/atender" element={<SommieRoomInquilino />} />
      </Routes>
    </div>
  );
}

export default App;
