import { useEffect, useState } from "react";
import peer from "../../service/peer";
import FireBaseConexion from "../../service/FireBase";
import { useLocation } from "react-router-dom";

export default function useSommieRoomInquilino() {

    const querystring = new URLSearchParams(useLocation().search);
    let piso = querystring.get("Piso");
    let departamento = querystring.get("Departamento");

    const [callStream, setCallStream] = useState(null);
    const fireBase = new FireBaseConexion();
    const [callStreamReal, setCallStreamReal] = useState(null)
    const [ultimoSdp, setUltimoSdp] = useState()
    const [recibiendoLlamada, setRecibiendoLlamada] = useState(false)

    useEffect(() => {
        peer.peer.addEventListener("track", (ev) => {
            const remoteStream = ev.streams[0];
            console.log(remoteStream)
            setCallStream(remoteStream);

        });



        ///ESCUCHA EL FIREBASE DEL LADO DEL PORTERO
        const handlePorteroChanges = (data) => {
            if (data != undefined) {
                switch (data.etapa) {
                    case 'conexion': setearTracks(data.sdpPortero, 'tracks'); ///La etapa indica lo que tiene que hacer el otro lado
                        break;
                    case 'seteaTracks': setearOffer(data?.sdpPortero, 'stream');
                        break;
                    case 'unaMas': setearOffer(data?.sdpPortero, 'anteUltimo');
                        break;
                    case 'dosMas': setearOffer(data?.sdpPortero, 'fin');
                        break;
                    case 'seteaStream': setUltimoSdp(data.sdpPortero)
                        break;
                }

                console.log('Cambios en los datos del Portero:', data);
            }


        };

        fireBase.listenPorteroChanges(piso, departamento, handlePorteroChanges);
        // Limpiar el listener cuando el componente se desmonta
        return () => {
            fireBase.stopListeningPorteroChanges(piso, departamento);
        };



    }, [])

    const setearTracks = async (sdp, etapa) => {
        const sessionDescription = new RTCSessionDescription({
            type: 'offer',
            sdp: sdp.replace(/\\r/g, '\r').replace(/\\n/g, '\n')
        });

        const stream = await navigator.mediaDevices.getUserMedia({
            audio: true,
            video: true,
        });

        stream.getTracks().map(track => peer.peer.addTrack(track, stream))
        const ans = await peer.getAnswer(sessionDescription);
        fireBase.setDataInquilino(piso, departamento, ans.sdp, etapa)
    }

    const setearOffer = async (sdp, etapa) => {
        console.log(etapa)
        const sessionDescription = new RTCSessionDescription({
            type: 'offer',
            sdp: sdp.replace(/\\r/g, '\r').replace(/\\n/g, '\n')
        });
        const ans = await peer.getAnswer(sessionDescription);
        if (etapa === 'fin') setRecibiendoLlamada(true)
        fireBase.setDataInquilino(piso, departamento, ans.sdp, etapa)
    }


    const atender = async () => {
        const sessionDescription = new RTCSessionDescription({
            type: 'offer',
            sdp: ultimoSdp.replace(/\\r/g, '\r').replace(/\\n/g, '\n')
        });
        await peer.getAnswer(sessionDescription);
        fireBase.setInquilinoAtendio(piso, departamento)
        setCallStreamReal(callStream)
        if (window.ReactNativeWebView) window.ReactNativeWebView.postMessage(JSON.stringify({estado: 'true' }));


    }


    return {
        callStreamReal,
        atender,
        recibiendoLlamada

    };
}