import { initializeApp } from "firebase/app";
import { getAnalytics } from "firebase/analytics";
import { getDatabase, ref, set, onValue, off,remove  } from "firebase/database";

class FireBaseConexion {
    constructor() {
        this.firebaseConfig = {
            apiKey: "AIzaSyCPeKJgJRp_ujgF8Bdxkxpp-EH0b4bGhQo",
            authDomain: "sommieringrtc.firebaseapp.com",
            databaseURL: "https://sommieringrtc-default-rtdb.firebaseio.com",
            projectId: "sommieringrtc",
            storageBucket: "sommieringrtc.appspot.com",
            messagingSenderId: "1048197500371",
            appId: "1:1048197500371:web:776f300966dd2ad1daf326",
            measurementId: "G-2T14TL6Z9S"
        };

        // Inicializar Firebase
        this.app = initializeApp(this.firebaseConfig);
        this.analytics = getAnalytics(this.app);

        // Obtener una referencia a la base de datos
        this.db = getDatabase();
    }
    // Metodo para borrar base
    limpiarDataBase(piso,departamento) {
        const dataRef = ref(this.db, `/${piso}/${departamento}`);
        remove(dataRef)
            .then(() => {
                console.log('Base de datos limpia correctamente.');
            })
            .catch((error) => {
                console.error('Error al limpiar la base de datos:', error);
            });
    }

    // Método para establecer datos en la base de datos
    setDataPortero(piso,departamento,newSdp,etapa) {
        const dataRef = ref(this.db, `/${piso}/${departamento}/Portero`);
        const newData = {
            sdpPortero: newSdp,
            etapa:etapa
        };

        this.setDataBase(dataRef, newData);
    }

    setDataInquilino(piso,departamento,newSdp,etapa) {
        const dataRef = ref(this.db, `/${piso}/${departamento}/Inquilino`);
        const newData = {
            sdpInquilino: newSdp,
            etapa: etapa
        };

        this.setDataBase(dataRef, newData);
    }

    setInquilinoAtendio(piso,departamento) {
        const dataRef = ref(this.db, `/${piso}/${departamento}/Inquilino`);
        const newData = {
            etapa: 'atendio'
        };

        this.setDataBase(dataRef, newData);
    }



    // Método privado para establecer los datos en la base de datos
    setDataBase(dataRef, newData) {
        set(dataRef, newData)
            .then(() => {
                console.log('Datos establecidos correctamente en la base de datos.');
            })
            .catch((error) => {
                console.error('Error al establecer los datos:', error);
            });
    }

    listenPorteroChanges(piso,departamento,callback) {
        const porteroRef = ref(this.db, `/${piso}/${departamento}/Portero`);
        onValue(porteroRef, (snapshot) => {
            const data = snapshot.val();
            callback(data);
        });
    }

    // Método para detener la escucha de los cambios en la base de datos del Portero
    stopListeningPorteroChanges(piso,departamento) {
        const porteroRef = ref(this.db, `/${piso}/${departamento}/Portero`);
        off(porteroRef);
    }

    listenInquilinoChanges(piso,departamento,callback) {
        const inquilinoRef = ref(this.db, `/${piso}/${departamento}/Inquilino`);
        onValue(inquilinoRef, (snapshot) => {
            const data = snapshot.val();
            callback(data);
        });
    }

    // Método para detener la escucha de los cambios en la base de datos del Portero
    stopListenInquilinoChanges(piso,departamento) {
        const inquilinoRef = ref(this.db, `/${piso}/${departamento}/Inquilino`);
        off(inquilinoRef);
    }

   
}

export default FireBaseConexion;
