import React from "react";
import ReactPlayer from "react-player";
import '../SommieRoomInquilino.css';
import useSommieRoomPortero from "./useSommieRoomPortero";
import './SommieRoomPortero.css'
const SommieRoomPortero = () => {

  const { callStreamReal,piso,departamento } = useSommieRoomPortero()


  return (
    <div className="container-call">
      <div className="container-llamada">
        <div className="call-screen">
          <div className="notification-bar">
            <div className="hora-bar">
              <h3>23:13</h3>
            </div>
            <div className="titulo-bar">
              <h3>CONSORCIO JUAN DOMINGO PERON</h3>
            </div>
          </div>
          <div className="caller-info">
            <>
              {callStreamReal ? (
                <ReactPlayer
                  playing
                  height="100%"
                  width="100%"
                  url={callStreamReal}
                />
              ) : (
                <>
                  <h1 className="caller-name">Piso {piso} Dpto {departamento} </h1>
                  <p className="caller-detail">Llamando...</p>
                </>

              )}
            </>
          </div>

        </div>
      </div>
    </div>
  );
};
export default SommieRoomPortero;