import { useEffect, useCallback, useState } from "react";
import peer from "../../service/peer";
import FireBaseConexion from "../../service/FireBase";
import { useLocation } from "react-router-dom";

export default function useSommieRoomPortero() {

    const querystring = new URLSearchParams(useLocation().search);
    let piso = querystring.get("Piso");
    let departamento = querystring.get("Departamento");

    const [myStream, setMyStream] = useState(null);
    const [callStreamReal, setCallStreamReal] = useState(null)
    const fireBase = new FireBaseConexion();

    useEffect(() => {
        fireBase.limpiarDataBase(piso,departamento)
        InitCall();
    }, []);

    ///CREA INSTANCIA STREAM
    const InitCall = useCallback(async () => {
        const stream = await navigator.mediaDevices.getUserMedia({
            audio: true,
            video: true,
        });
        setMyStream(stream);
    });

    useEffect(() => {
        //cuando se detecta un mediaDevice se setea el stream inquilino
        peer.peer.addEventListener("track", (ev) => {
            const remoteStream = ev.streams[0];
            setMyStream(myStream);
            localStorage.setItem('streamInquilino', remoteStream);
            // Guardar algo útil pero serializable, por ejemplo, IDs de track
            const trackIds = remoteStream.getTracks().map(track => track.id);
            localStorage.setItem('streamTrackIds', JSON.stringify(trackIds));
        });

        if (myStream) {
            generarOffer('conexion')
            ///ESCUCHA EL FIREBASE DEL LADO DEL INQUILINO
            const handleInquilinoChanges = (data) => {
                if (data != undefined) {
                    switch (data.etapa) {
                        case 'tracks': agregarTracks(data?.sdpInquilino, 'seteaTracks'); ///La etapa indica lo que tiene que hacer el otro lado
                            break;
                        case 'stream': generarStream(data?.sdpInquilino, 'unaMas')
                            break;
                        case 'anteUltimo': generarStream(data?.sdpInquilino, 'dosMas')
                            break;
                        case 'fin': generarStream(data?.sdpInquilino, 'seteaStream')
                            break;
                        case 'atendio': atender()
                            break;
                    }

                }

            };

            fireBase.listenInquilinoChanges(piso,departamento,handleInquilinoChanges);

            // Limpiar el listener cuando el componente se desmonta
            return () => {
                fireBase.stopListenInquilinoChanges(piso,departamento);
            };
        }


    }, [myStream])

    const generarOffer = useCallback(async (etapa) => {


        // Obtener la oferta con los tracks incluidos en el SDP
        const offer = await peer.getOffer();
        fireBase.setDataPortero(piso,departamento,offer.sdp, etapa)

    });

    const agregarTracks = async (sdp, etapa) => {
        const sessionDescription = new RTCSessionDescription({
            type: 'answer',
            sdp: sdp?.replace(/\\r/g, '\r').replace(/\\n/g, '\n') // Proporciona la cadena de texto SDP
        });
        await peer.setRemoteDescription(sessionDescription)
        await myStream.getTracks().map(track => peer.peer.addTrack(track, myStream))
        generarOffer(etapa);

    }

    const generarStream = async (sdp, etapa) => {
        const sessionDescription = new RTCSessionDescription({
            type: 'answer',
            sdp: sdp?.replace(/\\r/g, '\r').replace(/\\n/g, '\n')
        });
        await peer.setRemoteDescription(sessionDescription)
        generarOffer(etapa);
    };


    const atender = () => {
        const trackIds = localStorage.getItem('streamTrackIds');
        const parsedTrackIds = JSON.parse(trackIds);

        console.log(parsedTrackIds);

        // Ahora necesitas obtener las pistas reales basadas en estos IDs
        reconstruirStream(parsedTrackIds);

    }

    const reconstruirStream = (trackIds) => {
        if (!peer) {
            console.log("No hay una conexión de peer disponible.");
            return;
        }

        let newStream = new MediaStream();

        // Obtener todas las pistas del sender de la conexión peer
        const senders = peer.peer.getSenders();
        senders.forEach(sender => {
            if (sender.track && trackIds.includes(sender.track.id)) {
                newStream.addTrack(sender.track);
            }
        });

        // También puedes verificar los receivers si es necesario
        const receivers = peer.peer.getReceivers();
        receivers.forEach(receiver => {
            if (receiver.track && trackIds.includes(receiver.track.id)) {
                newStream.addTrack(receiver.track);
            }
        });

        setCallStreamReal(newStream);
    }




    return {
        callStreamReal,
        piso,
        departamento
    };
}